using CommunityToolkit.Mvvm.ComponentModel;

using WhateverDotNet.TestApp.Components.Controls;
using WhateverDotNet.TestApp.Components.Pages;

namespace WhateverDotNet.TestApp.Components.Navigation;

public partial class NavigationMenuViewModel
    : HamburgerMenuViewModel<PageModel>,
        IDisposable
{
    private readonly INavigationStore _navigationStore;

    [ObservableProperty]
    private NavigationMenuItemViewModel? _selectedNavigationItem;

    [ObservableProperty]
    private NavigationMenuItemViewModel? _selectedSupportItem;

    public NavigationMenuViewModel(INavigationStore navigationStore)
    {
        _navigationStore = navigationStore
            ?? throw new ArgumentNullException(nameof(navigationStore));

        _navigationStore.CurrentPageChanged += OnCurrentPageChanged;

        foreach (var page in _navigationStore.Pages)
        {
            TopMenuItems.Add(new NavigationMenuItemViewModel(page));
        }

        foreach (var page in _navigationStore.SupportPages)
        {
            BottomMenuItems.Add(new NavigationMenuItemViewModel(page));
        }
    }

