    public void Dispose()
    {
        _navigationStore.CurrentPageChanged -= OnCurrentPageChanged;
    }

    protected override void SelectItem(HamburgerMenuItemViewModel<PageModel>? item)
    {
        if (item is not NavigationMenuItemViewModel navigationItem)
        {
            return;
        }

        _navigationStore.SetCurrentPage(navigationItem.Model);
    }

    private void OnCurrentPageChanged()
    {
        SyncSelection();
    }

    private void SyncSelection()
    {
        var selected = _navigationStore.SelectedPage;
        NavigationMenuItemViewModel? navItem = null;
        NavigationMenuItemViewModel? supportItem = null;

        foreach (NavigationMenuItemViewModel item in TopMenuItems)
        {
            item.IsSelected = ReferenceEquals(item.Model, selected);
            if (item.IsSelected)
            {
                navItem = item;
            }
        }

        foreach (NavigationMenuItemViewModel item in BottomMenuItems)
        {
            item.IsSelected = ReferenceEquals(item.Model, selected);
            if (item.IsSelected)
            {
                supportItem = item;
            }
        }

        SelectedNavigationItem = navItem;
        SelectedSupportItem = supportItem;
    }
}